+// runPoll processes events by periodically scanning watched paths when fsnotify is unavailable.
+func (w *Watcher) runPoll() {
+	ticker := time.NewTicker(w.pollInterval)
+	defer ticker.Stop()
+
+	for {
+		select {
+		case <-ticker.C:
+			w.pollOnce()
+		case <-w.closeCh:
+			return
+		}
+	}
+}
